Another solution I have found is to handle (remove) the unclosing tags before opening it with `exceljs`.

A .xlsx file is just a zip containing some .xml files. So if you can identify the unclosing tags, you can remove them like this: Rename .xlsx file to .zip -> Unzip it -> Rename file content needed -> Zip it -> Go back .xlsx.

Example:

```ts
import AdmZip from 'adm-zip'

/**
 * Prepare excel file: Rename to Zip -> Unzip -> Rename file content needed -> Zip folder -> Go back to original format
 * @param filePath filePath
 */
async function prepare(filePath: string): Promise<void> {
    const folderPath = filePath.replace(/\.[^/.]+$/, '')
    const zipPath = `${folderPath}.zip`

    // Rename .xlsx to .zip
    await rename(filePath, zipPath)

    // Unzip content to folder
    const unzip = new AdmZip(zipPath)
    await new Promise((resolve, reject) => {
        unzip.extractAllToAsync(folderPath, true, true, (error: never) => {
            if (error) {
                reject(error)
            } else {
                resolve('')
            }
        })
    })

    // Remove zip file
    await unlink(zipPath)

    /**
     * Get all files recursively
     * @param path path
     */
    const walk = (path: string): Array<string> =>
        readdirSync(path, { withFileTypes: true }).flatMap(file =>
            file.isDirectory() ? walk(join(path, file.name)) : join(path, file.name),
        )

    /** List of all files decompressed */
    const files = walk(folderPath)

    // Apply all transformation needed
    await Promise.all(
        files
            .filter(path => path.endsWith('.vml'))
            .map(async path => {
                // Remove problematic elements
                const content = await readFile(path, 'utf-8')
                const newContent = content.replace(/<br>/g, '')
                await writeFile(path, newContent)
            }),
    )

    // Create a new zip
    const zip = new AdmZip()
    zip.addLocalFolder(folderPath)
    await zip.writeZipPromise(zipPath)

    // Remove folder
    await rm(folderPath, { recursive: true, force: true })

    // Rename .zip to .xlsx
    await rename(zipPath, filePath)
}
```
